import React, { useState, useEffect } from 'react';
import { CourseConfig, AppView } from './types';
import { INITIAL_COURSE_DATA } from './constants';
import StudentArea from './components/StudentArea';
import AdminArea from './components/AdminArea';
import { Layout, Settings, GraduationCap } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('student');
  const [courseData, setCourseData] = useState<CourseConfig>(() => {
    const saved = localStorage.getItem('nexus_course_data');
    return saved ? JSON.parse(saved) : INITIAL_COURSE_DATA;
  });

  useEffect(() => {
    localStorage.setItem('nexus_course_data', JSON.stringify(courseData));
  }, [courseData]);

  const handleUpdateCourse = (newData: CourseConfig) => {
    setCourseData(newData);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* View Switcher Header */}
      <header className="fixed top-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-3 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white font-bold">N</div>
          <span className="font-bold text-slate-800 tracking-tight">Nexus LMS</span>
        </div>

        <nav className="flex gap-2">
          <button
            onClick={() => setView('student')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all ${
              view === 'student' 
                ? 'bg-indigo-600 text-white shadow-md' 
                : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
            }`}
          >
            <GraduationCap size={18} />
            Área do Aluno
          </button>
          <button
            onClick={() => setView('admin')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium transition-all ${
              view === 'admin' 
                ? 'bg-indigo-600 text-white shadow-md' 
                : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
            }`}
          >
            <Settings size={18} />
            Painel Admin
          </button>
        </nav>
      </header>

      <main className="flex-1 pt-16">
        {view === 'student' ? (
          <StudentArea course={courseData} />
        ) : (
          <AdminArea course={courseData} onUpdate={handleUpdateCourse} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { CourseConfig, Lesson } from '../types';
import { Play, ChevronRight, ChevronDown, CheckCircle2, Headphones, MessageSquare, Star } from 'lucide-react';

interface StudentAreaProps {
  course: CourseConfig;
}

const StudentArea: React.FC<StudentAreaProps> = ({ course }) => {
  const [selectedLesson, setSelectedLesson] = useState<Lesson>(course.modules[0].lessons[0]);
  const [openModules, setOpenModules] = useState<string[]>([course.modules[0].id]);
  const [completedLessons, setCompletedLessons] = useState<string[]>([]);

  const toggleModule = (id: string) => {
    setOpenModules(prev => 
      prev.includes(id) ? prev.filter(m => m !== id) : [...prev, id]
    );
  };

  const toggleComplete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setCompletedLessons(prev => 
      prev.includes(id) ? prev.filter(l => l !== id) : [...prev, id]
    );
  };

  const progress = Math.round((completedLessons.length / course.modules.flatMap(m => m.lessons).length) * 100);

  return (
    <div className="flex flex-col lg:flex-row h-[calc(100vh-64px)] overflow-hidden">
      {/* Sidebar Navigation */}
      <aside className="w-full lg:w-80 bg-white border-r border-slate-200 flex flex-col">
        <div className="p-6 border-b border-slate-100 bg-slate-50/50">
          <div className="flex items-center gap-4 mb-4">
            <img src={course.logoUrl} alt="Logo" className="w-12 h-12 rounded-xl object-cover shadow-sm" />
            <div>
              <h2 className="font-bold text-slate-800 line-clamp-1">{course.name}</h2>
              <p className="text-xs text-slate-500 font-medium">{course.instructorName}</p>
            </div>
          </div>
          <div className="space-y-1.5">
            <div className="flex justify-between text-xs font-semibold text-slate-600 mb-1">
              <span>Seu Progresso</span>
              <span>{progress}%</span>
            </div>
            <div className="h-1.5 w-full bg-slate-200 rounded-full overflow-hidden">
              <div 
                className="h-full bg-indigo-600 transition-all duration-500" 
                style={{ width: `${progress}%` }}
              />
            </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-2">
          {course.modules.map((module, idx) => (
            <div key={module.id} className="mb-2">
              <button 
                onClick={() => toggleModule(module.id)}
                className="w-full flex items-center justify-between p-3 rounded-lg hover:bg-slate-50 transition-colors text-left group"
              >
                <div className="flex items-center gap-3">
                  <span className="flex items-center justify-center w-6 h-6 rounded-md bg-slate-100 text-slate-500 text-[10px] font-bold group-hover:bg-indigo-100 group-hover:text-indigo-600 transition-colors">
                    {idx + 1}
                  </span>
                  <span className="font-semibold text-sm text-slate-700">{module.title}</span>
                </div>
                {openModules.includes(module.id) ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
              </button>

              {openModules.includes(module.id) && (
                <div className="mt-1 space-y-1 pl-4">
                  {module.lessons.map((lesson) => (
                    <button
                      key={lesson.id}
                      onClick={() => setSelectedLesson(lesson)}
                      className={`w-full flex items-center gap-3 p-3 rounded-lg transition-all text-left ${
                        selectedLesson.id === lesson.id 
                          ? 'bg-indigo-50 border-l-4 border-indigo-600' 
                          : 'hover:bg-slate-50'
                      }`}
                    >
                      <div 
                        onClick={(e) => toggleComplete(e, lesson.id)}
                        className={`shrink-0 flex items-center justify-center w-5 h-5 rounded-full border ${
                          completedLessons.includes(lesson.id) 
                            ? 'bg-green-500 border-green-500 text-white' 
                            : 'border-slate-300'
                        }`}
                      >
                        {completedLessons.includes(lesson.id) && <CheckCircle2 size={12} />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className={`text-sm font-medium truncate ${selectedLesson.id === lesson.id ? 'text-indigo-900' : 'text-slate-600'}`}>
                          {lesson.title}
                        </p>
                        <p className="text-[10px] text-slate-400 font-medium">{lesson.duration}</p>
                      </div>
                      {selectedLesson.id === lesson.id && <Play size={14} className="text-indigo-600 fill-indigo-600" />}
                    </button>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>

        <div className="p-4 border-t border-slate-100">
          <a 
            href={course.supportUrl} 
            target="_blank" 
            rel="noreferrer"
            className="flex items-center justify-center gap-2 w-full py-3 rounded-xl bg-slate-900 text-white font-semibold text-sm hover:bg-slate-800 transition-all shadow-lg shadow-slate-200"
          >
            <Headphones size={18} />
            Suporte Individual
          </a>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 bg-slate-50 overflow-y-auto custom-scrollbar">
        <div className="max-w-5xl mx-auto p-4 lg:p-8">
          {/* Video Player Container */}
          <div className="relative aspect-video bg-black rounded-3xl overflow-hidden shadow-2xl mb-8 group">
            <iframe
              src={selectedLesson.videoUrl}
              className="w-full h-full"
              allowFullScreen
              title={selectedLesson.title}
            ></iframe>
          </div>

          <div className="flex flex-col lg:flex-row gap-8">
            <div className="flex-1">
              <div className="flex items-center justify-between mb-6">
                <div>
                  <h1 className="text-2xl lg:text-3xl font-bold text-slate-900 mb-2">{selectedLesson.title}</h1>
                  <div className="flex items-center gap-4">
                    <span className="flex items-center gap-1.5 px-3 py-1 rounded-full bg-indigo-100 text-indigo-700 text-xs font-bold">
                      <Play size={12} /> {selectedLesson.duration}
                    </span>
                    <span className="text-sm text-slate-500 font-medium">Postado há 2 dias</span>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button className="p-2.5 rounded-xl border border-slate-200 hover:bg-white text-slate-600 transition-all shadow-sm">
                    <Star size={20} />
                  </button>
                  <button className="p-2.5 rounded-xl border border-slate-200 hover:bg-white text-slate-600 transition-all shadow-sm">
                    <MessageSquare size={20} />
                  </button>
                </div>
              </div>

              <div className="bg-white rounded-2xl p-6 lg:p-8 shadow-sm border border-slate-100">
                <h3 className="font-bold text-slate-800 mb-4 text-lg">Sobre esta aula</h3>
                <p className="text-slate-600 leading-relaxed whitespace-pre-line">
                  {selectedLesson.description}
                </p>
              </div>
            </div>

            {/* Side Action Cards */}
            <div className="w-full lg:w-72 space-y-6">
              <div className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-2xl p-6 text-white shadow-xl shadow-indigo-100">
                <h4 className="font-bold mb-2">Comunidade VIP</h4>
                <p className="text-indigo-100 text-sm mb-4">Acesse nosso grupo exclusivo no Discord e tire suas dúvidas em tempo real.</p>
                <button className="w-full py-2.5 bg-white text-indigo-600 rounded-xl font-bold text-sm hover:bg-indigo-50 transition-colors">
                  Acessar Grupo
                </button>
              </div>

              <div className="bg-white rounded-2xl p-5 border border-slate-200">
                <h4 className="font-bold text-slate-800 mb-4 text-sm">Materiais de Apoio</h4>
                <div className="space-y-3">
                  <button className="w-full text-left p-3 rounded-lg bg-slate-50 hover:bg-slate-100 border border-dashed border-slate-300 text-slate-500 text-xs font-medium transition-all">
                    Nenhum arquivo anexado
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default StudentArea;

import React, { useState } from 'react';
import { CourseConfig, Module, Lesson } from '../types';
import { 
  Save, Plus, Trash2, Edit3, Image as ImageIcon, Layout as LayoutIcon, 
  MessageCircle, Video, List, MoveUp, MoveDown, CheckCircle 
} from 'lucide-react';

interface AdminAreaProps {
  course: CourseConfig;
  onUpdate: (newData: CourseConfig) => void;
}

const AdminArea: React.FC<AdminAreaProps> = ({ course, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<'general' | 'modules' | 'appearance'>('general');
  const [formData, setFormData] = useState<CourseConfig>(course);
  const [showSaveToast, setShowSaveToast] = useState(false);

  const handleSave = () => {
    onUpdate(formData);
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const addModule = () => {
    const newModule: Module = {
      id: `mod-${Date.now()}`,
      title: 'Novo Módulo',
      lessons: []
    };
    setFormData(prev => ({ ...prev, modules: [...prev.modules, newModule] }));
  };

  const addLesson = (moduleId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: [...m.lessons, {
              id: `les-${Date.now()}`,
              title: 'Nova Aula',
              videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ',
              description: 'Descrição da aula...',
              duration: '10:00'
            }]
          };
        }
        return m;
      })
    }));
  };

  const deleteModule = (moduleId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.filter(m => m.id !== moduleId)
    }));
  };

  const deleteLesson = (moduleId: string, lessonId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: m.lessons.filter(l => l.id !== lessonId)
          };
        }
        return m;
      })
    }));
  };

  const updateModuleTitle = (moduleId: string, title: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === moduleId ? { ...m, title } : m)
    }));
  };

  const updateLesson = (moduleId: string, lessonId: string, updates: Partial<Lesson>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: m.lessons.map(l => l.id === lessonId ? { ...l, ...updates } : l)
          };
        }
        return m;
      })
    }));
  };

  return (
    <div className="max-w-6xl mx-auto p-6 lg:p-10 relative">
      {/* Toast Notification */}
      {showSaveToast && (
        <div className="fixed bottom-10 right-10 z-[100] animate-bounce bg-green-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-3">
          <CheckCircle size={20} />
          <span className="font-bold">Configurações salvas com sucesso!</span>
        </div>
      )}

      <div className="flex flex-col lg:flex-row items-start lg:items-center justify-between mb-10 gap-6">
        <div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">Configurações da Área de Membros</h1>
          <p className="text-slate-500 mt-1">Gerencie seu conteúdo, branding e experiência do aluno.</p>
        </div>
        <button 
          onClick={handleSave}
          className="flex items-center gap-2 px-8 py-3 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 group"
        >
          <Save size={20} className="group-hover:scale-110 transition-transform" />
          Salvar Alterações
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        {/* Navigation Tabs */}
        <div className="lg:col-span-3 space-y-2">
          <button 
            onClick={() => setActiveTab('general')}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-2xl font-semibold transition-all ${
              activeTab === 'general' ? 'bg-white text-indigo-600 shadow-md ring-1 ring-slate-200' : 'text-slate-500 hover:bg-slate-100'
            }`}
          >
            <LayoutIcon size={20} /> Geral
          </button>
          <button 
            onClick={() => setActiveTab('modules')}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-2xl font-semibold transition-all ${
              activeTab === 'modules' ? 'bg-white text-indigo-600 shadow-md ring-1 ring-slate-200' : 'text-slate-500 hover:bg-slate-100'
            }`}
          >
            <List size={20} /> Conteúdo
          </button>
          <button 
            onClick={() => setActiveTab('appearance')}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-2xl font-semibold transition-all ${
              activeTab === 'appearance' ? 'bg-white text-indigo-600 shadow-md ring-1 ring-slate-200' : 'text-slate-500 hover:bg-slate-100'
            }`}
          >
            <ImageIcon size={20} /> Visual
          </button>
        </div>

        {/* Form Content */}
        <div className="lg:col-span-9 space-y-8">
          {activeTab === 'general' && (
            <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Nome do Curso</label>
                  <input 
                    type="text" 
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">Instrutor</label>
                  <input 
                    type="text" 
                    value={formData.instructorName}
                    onChange={(e) => setFormData({...formData, instructorName: e.target.value})}
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Descrição</label>
                <textarea 
                  value={formData.description}
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  rows={4}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none"
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">Link de Suporte (WhatsApp)</label>
                <div className="relative">
                  <MessageCircle size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    value={formData.supportUrl}
                    onChange={(e) => setFormData({...formData, supportUrl: e.target.value})}
                    placeholder="https://wa.me/..."
                    className="w-full pl-12 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                  />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'modules' && (
            <div className="space-y-6">
              {formData.modules.map((mod) => (
                <div key={mod.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
                  <div className="p-5 bg-slate-50 flex items-center justify-between border-b border-slate-200">
                    <div className="flex items-center gap-4 flex-1">
                      <Edit3 size={18} className="text-slate-400" />
                      <input 
                        type="text"
                        value={mod.title}
                        onChange={(e) => updateModuleTitle(mod.id, e.target.value)}
                        className="bg-transparent font-bold text-slate-800 outline-none focus:border-b border-indigo-500 pb-0.5 w-full"
                      />
                    </div>
                    <div className="flex items-center gap-2">
                      <button onClick={() => deleteModule(mod.id)} className="p-2 text-slate-400 hover:text-red-500 transition-colors">
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>

                  <div className="p-6 space-y-4">
                    {mod.lessons.map((lesson) => (
                      <div key={lesson.id} className="p-5 rounded-2xl bg-slate-50 border border-slate-100 space-y-4">
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-3">
                            <Video size={18} className="text-indigo-600" />
                            <input 
                              type="text"
                              value={lesson.title}
                              onChange={(e) => updateLesson(mod.id, lesson.id, { title: e.target.value })}
                              className="bg-transparent font-semibold text-slate-700 outline-none focus:border-b border-indigo-400"
                            />
                          </div>
                          <button onClick={() => deleteLesson(mod.id, lesson.id)} className="text-slate-400 hover:text-red-500 transition-colors">
                            <Trash2 size={16} />
                          </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                          <div className="space-y-1">
                            <label className="text-[10px] font-black uppercase text-slate-400">Embed URL do Vídeo</label>
                            <input 
                              type="text"
                              value={lesson.videoUrl}
                              onChange={(e) => updateLesson(mod.id, lesson.id, { videoUrl: e.target.value })}
                              className="w-full px-3 py-2 rounded-lg border border-slate-200 text-xs outline-none"
                            />
                          </div>
                          <div className="space-y-1">
                            <label className="text-[10px] font-black uppercase text-slate-400">Duração</label>
                            <input 
                              type="text"
                              value={lesson.duration}
                              onChange={(e) => updateLesson(mod.id, lesson.id, { duration: e.target.value })}
                              className="w-full px-3 py-2 rounded-lg border border-slate-200 text-xs outline-none"
                            />
                          </div>
                        </div>
                        <div className="space-y-1">
                          <label className="text-[10px] font-black uppercase text-slate-400">Conteúdo da Aula</label>
                          <textarea 
                            value={lesson.description}
                            onChange={(e) => updateLesson(mod.id, lesson.id, { description: e.target.value })}
                            rows={2}
                            className="w-full px-3 py-2 rounded-lg border border-slate-200 text-xs outline-none resize-none"
                          />
                        </div>
                      </div>
                    ))}

                    <button 
                      onClick={() => addLesson(mod.id)}
                      className="w-full py-4 border-2 border-dashed border-slate-200 rounded-2xl flex items-center justify-center gap-2 text-slate-400 font-bold text-sm hover:border-indigo-300 hover:text-indigo-500 transition-all group"
