                    </button>
                  </div>
                </div>
              ))}

              <button 
                onClick={addModule}
                className="w-full py-6 bg-slate-900 text-white rounded-3xl flex items-center justify-center gap-3 font-bold shadow-xl shadow-slate-200 hover:scale-[1.01] transition-all active:scale-[0.99]"
