                <Plus size={24} />
                Criar Novo Módulo
              </button>
            </div>
          )}

          {activeTab === 'appearance' && (
            <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 space-y-10">
              <div className="space-y-4">
                <h3 className="font-bold text-slate-800">Identidade Visual</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-4">
                    <label className="text-sm font-bold text-slate-700">Logo (URL)</label>
                    <div className="flex gap-4">
                      <img src={formData.logoUrl} className="w-16 h-16 rounded-2xl object-cover bg-slate-100" />
                      <input 
                        type="text" 
                        value={formData.logoUrl}
                        onChange={(e) => setFormData({...formData, logoUrl: e.target.value})}
                        className="flex-1 px-4 py-2 h-10 my-auto rounded-xl border border-slate-200 text-xs"
                      />
                    </div>
                  </div>
                  <div className="space-y-4">
                    <label className="text-sm font-bold text-slate-700">Cor Principal</label>
                    <div className="flex gap-4 items-center">
                      <input 
                        type="color" 
                        value={formData.accentColor}
                        onChange={(e) => setFormData({...formData, accentColor: e.target.value})}
                        className="w-12 h-12 rounded-lg overflow-hidden border-none"
                      />
                      <input 
                        type="text" 
                        value={formData.accentColor}
                        onChange={(e) => setFormData({...formData, accentColor: e.target.value})}
                        className="flex-1 px-4 py-2 rounded-xl border border-slate-200 text-xs font-mono"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="space-y-4 pt-6 border-t border-slate-100">
                <h3 className="font-bold text-slate-800">Capa do Curso</h3>
                <div className="space-y-4">
                  <div className="w-full aspect-video md:aspect-[3/1] rounded-3xl bg-slate-100 overflow-hidden relative group">
                    <img src={formData.bannerUrl} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity cursor-pointer">
                      <ImageIcon size={32} className="text-white" />
                    </div>
                  </div>
                  <input 
                    type="text" 
                    value={formData.bannerUrl}
                    onChange={(e) => setFormData({...formData, bannerUrl: e.target.value})}
                    placeholder="URL da Imagem de Capa"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 text-sm"
                  />
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

