import React, { useState, useEffect } from 'react';
import { CourseConfig, AppView } from './types';
import { INITIAL_COURSE_DATA } from './constants';
import StudentArea from './components/StudentArea';
import AdminArea from './components/AdminArea';
import { ChevronLeft, User, Bell, Search, Settings } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('student');
  const [courseData, setCourseData] = useState<CourseConfig>(() => {
    const saved = localStorage.getItem('nexus_course_data_v2');
    return saved ? JSON.parse(saved) : INITIAL_COURSE_DATA;
  });

  useEffect(() => {
    localStorage.setItem('nexus_course_data_v2', JSON.stringify(courseData));
  }, [courseData]);

  const handleUpdateCourse = (newData: CourseConfig) => {
    setCourseData(newData);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white flex flex-col font-sans selection:bg-amber-500 selection:text-black">
      {/* Top Bar Producer Style */}
      <header className="fixed top-0 left-0 right-0 z-[100] h-14 bg-[#111] border-b border-white/10 flex items-center justify-between px-6">
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setView('student')}
            className="text-white/60 hover:text-white flex items-center gap-2 text-sm transition-colors"
          >
            <ChevronLeft size={18} />
            <span>Configurações</span>
          </button>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3 text-sm">
            <span className="text-white/60">Visualizando como:</span>
            <div className="relative group">
              <button 
                onClick={() => setView(view === 'admin' ? 'student' : 'admin')}
                className="bg-white/5 border border-white/10 px-4 py-1.5 rounded flex items-center gap-2 hover:bg-white/10 transition-all font-medium"
              >
                {view === 'admin' ? 'Produtor' : 'Aluno'}
                <Settings size={14} className="text-white/40" />
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Area */}
      <main className="flex-1 mt-14 overflow-hidden">
        {view === 'student' ? (
          <StudentArea course={courseData} />
        ) : (
          <AdminArea course={courseData} onUpdate={handleUpdateCourse} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { CourseConfig, Module, Lesson } from '../types';
import { 
  Save, Plus, Trash2, Edit3, Image as ImageIcon, Layout as LayoutIcon, 
  MessageCircle, Video, List, CheckCircle, ChevronDown, ChevronUp
} from 'lucide-react';

interface AdminAreaProps {
  course: CourseConfig;
  onUpdate: (newData: CourseConfig) => void;
}

const AdminArea: React.FC<AdminAreaProps> = ({ course, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<'general' | 'modules' | 'appearance'>('modules');
  const [formData, setFormData] = useState<CourseConfig>(course);
  const [showSaveToast, setShowSaveToast] = useState(false);
  const [expandedModule, setExpandedModule] = useState<string | null>(formData.modules[0]?.id || null);

  const handleSave = () => {
    onUpdate(formData);
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const addModule = () => {
    const newModule: Module = {
      id: `mod-${Date.now()}`,
      title: 'Novo Módulo Premium',
      thumbnailUrl: 'https://images.unsplash.com/photo-1557683316-973673baf926?q=80&w=800&auto=format&fit=crop',
      lessons: []
    };
    setFormData(prev => ({ ...prev, modules: [...prev.modules, newModule] }));
    setExpandedModule(newModule.id);
  };

  const updateModule = (id: string, updates: Partial<Module>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === id ? { ...m, ...updates } : m)
    }));
  };

  const addLesson = (moduleId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: [...m.lessons, {
              id: `les-${Date.now()}`,
              title: 'Nova Aula de Elite',
              videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ',
              description: 'Conteúdo programático...',
              duration: '15:00'
            }]
          };
        }
        return m;
      })
    }));
  };

  const deleteModule = (moduleId: string) => {
    setFormData(prev => ({ ...prev, modules: prev.modules.filter(m => m.id !== moduleId) }));
  };

  const updateLesson = (moduleId: string, lessonId: string, updates: Partial<Lesson>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: m.lessons.map(l => l.id === lessonId ? { ...l, ...updates } : l)
          };
        }
        return m;
      })
    }));
  };

  const deleteLesson = (moduleId: string, lessonId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return { ...m, lessons: m.lessons.filter(l => l.id !== lessonId) };
        }
        return m;
      })
    }));
  };

  return (
    <div className="max-w-7xl mx-auto p-10 bg-[#0a0a0a] min-h-screen">
      {showSaveToast && (
        <div className="fixed bottom-10 right-10 z-[200] animate-in fade-in slide-in-from-bottom-5 duration-300 bg-amber-500 text-black px-8 py-4 rounded-xl shadow-2xl flex items-center gap-3">
          <CheckCircle size={24} />
          <span className="font-black uppercase tracking-tight">Publicado com Sucesso!</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-12">
        <div>
          <h1 className="text-4xl font-black tracking-tighter uppercase italic">Painel do Produtor</h1>
          <p className="text-white/40 mt-2 font-medium">Personalize a experiência premium dos seus alunos.</p>
        </div>
        <button 
          onClick={handleSave}
          className="bg-amber-500 text-black px-12 py-4 rounded font-black hover:bg-white transition-all shadow-xl shadow-amber-500/10 flex items-center gap-3"
        >
          <Save size={20} /> SALVAR ALTERAÇÕES
        </button>
      </div>

      <div className="grid grid-cols-12 gap-12">
        <div className="col-span-12 lg:col-span-3 space-y-4">
          <button 
            onClick={() => setActiveTab('general')}
            className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${
              activeTab === 'general' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'
            }`}
          >
            <LayoutIcon size={20} /> GERAL
          </button>
          <button 
            onClick={() => setActiveTab('modules')}
            className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${
              activeTab === 'modules' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'
            }`}
          >
            <List size={20} /> CONTEÚDO
          </button>
          <button 
            onClick={() => setActiveTab('appearance')}
            className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${
              activeTab === 'appearance' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'
            }`}
          >
            <ImageIcon size={20} /> VISUAL
          </button>
        </div>

        <div className="col-span-12 lg:col-span-9">
          {activeTab === 'general' && (
            <div className="bg-[#111] border border-white/5 rounded-2xl p-10 space-y-10">
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Nome do Treinamento</label>
                  <input 
                    type="text" 
                    value={formData.name}
                    onChange={(e) => setFormData({...formData, name: e.target.value})}
                    className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 focus:border-amber-500 transition-all outline-none"
                  />
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Instrutor</label>
                  <input 
                    type="text" 
                    value={formData.instructorName}
                    onChange={(e) => setFormData({...formData, instructorName: e.target.value})}
                    className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 focus:border-amber-500 transition-all outline-none"
                  />
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-white/40 uppercase tracking-widest">Descrição do Curso</label>
                <textarea 
                  value={formData.description}
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  rows={4}
                  className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 focus:border-amber-500 transition-all outline-none resize-none"
                />
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-white/40 uppercase tracking-widest">Link do Suporte Individual</label>
