                        <div className="space-y-3">
                          <label className="text-xs font-black text-white/40 uppercase tracking-widest">URL da Thumbnail</label>
                          <input 
                            type="text" 
                            value={mod.thumbnailUrl}
                            onChange={(e) => updateModule(mod.id, { thumbnailUrl: e.target.value })}
                            className="w-full bg-[#111] border border-white/10 rounded px-5 py-3 outline-none"
                          />
                        </div>
                      </div>

                      <div className="space-y-4">
                        <h4 className="text-sm font-bold flex items-center gap-3">
                          Aulas do Módulo <span className="text-white/20">({mod.lessons.length})</span>
                        </h4>
                        <div className="space-y-4">
                          {mod.lessons.map((lesson) => (
                            <div key={lesson.id} className="p-6 bg-[#111] border border-white/5 rounded-xl space-y-6">
                              <div className="flex items-center justify-between">
                                <input 
                                  value={lesson.title}
                                  onChange={(e) => updateLesson(mod.id, lesson.id, { title: e.target.value })}
                                  className="bg-transparent text-lg font-bold outline-none border-b border-white/5 focus:border-amber-500 w-1/2"
                                />
                                <button onClick={() => deleteLesson(mod.id, lesson.id)} className="text-white/10 hover:text-red-500 transition-colors">
                                  <Trash2 size={16} />
                                </button>
                              </div>
                              <div className="grid grid-cols-2 gap-6">
                                <div className="space-y-2">
                                  <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">Link Embed (YouTube/Vimeo/Panda)</label>
                                  <input 
                                    value={lesson.videoUrl}
                                    onChange={(e) => updateLesson(mod.id, lesson.id, { videoUrl: e.target.value })}
                                    className="w-full bg-black/50 border border-white/5 rounded px-4 py-2 text-xs outline-none"
                                  />
                                </div>
                                <div className="space-y-2">
                                  <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">Tempo de Aula</label>
                                  <input 
                                    value={lesson.duration}
                                    onChange={(e) => updateLesson(mod.id, lesson.id, { duration: e.target.value })}
                                    className="w-full bg-black/50 border border-white/5 rounded px-4 py-2 text-xs outline-none"
                                  />
                                </div>
                              </div>
                            </div>
                          ))}
                          <button 
                            onClick={() => addLesson(mod.id)}
                            className="w-full py-4 border-2 border-dashed border-white/5 rounded-xl text-white/20 font-bold hover:border-amber-500/30 hover:text-amber-500 transition-all flex items-center justify-center gap-2"
                          >
                            <Plus size={18} /> ADICIONAR NOVA AULA
                          </button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              ))}
              <button 
                onClick={addModule}
                className="w-full py-10 bg-white text-black font-black uppercase tracking-tighter rounded-2xl shadow-2xl hover:bg-amber-500 transition-all flex items-center justify-center gap-4 text-2xl italic"
              >
                <Plus size={32} /> Criar Novo Módulo de Elite
              </button>
            </div>
          )}

          {activeTab === 'appearance' && (
            <div className="bg-[#111] border border-white/5 rounded-2xl p-10 space-y-12">
              <div className="space-y-6">
                <h3 className="text-xl font-bold border-l-4 border-amber-500 pl-4">Identidade Visual</h3>
