          <div className="h-[1px] flex-1 mx-8 bg-white/5" />
        </div>

        {/* Modules Layout Logic */}
        <div className={course.moduleLayout === 'horizontal' 
          ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8" 
          : "flex flex-col gap-12"
        }>
          {course.modules.map((mod) => (
            <div key={mod.id} className={course.moduleLayout === 'horizontal' ? "" : "bg-white/5 rounded-3xl p-8 border border-white/10"}>
              {course.moduleLayout === 'vertical' && (
                <div className="flex items-center justify-between mb-8">
