              )}

              {/* LESSONS GRID (ALWAYS HORIZONTAL) */}
              <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
                {course.moduleLayout === 'horizontal' ? (
                  /* In horizontal module layout, we just show the module card which leads to the player */
                  <div 
                    className="group cursor-pointer relative"
                    onClick={() => enterLesson(mod)}
