                  </div>
                ) : (
                  /* In vertical module layout, we show the lessons within the module horizontally */
                  mod.lessons.map((lesson) => (
                    <div 
                      key={lesson.id} 
                      className="group cursor-pointer"
                      onClick={() => enterLesson(mod, lesson)}
