                      <div className="relative aspect-video rounded-lg overflow-hidden ring-1 ring-white/10 group-hover:ring-amber-500/50 transition-all">
                        <img src={lesson.thumbnailUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
