import React, { useState } from 'react';
import { CourseConfig, Module, Lesson } from '../types';
import { 
  Save, Plus, Trash2, Edit3, Image as ImageIcon, Layout as LayoutIcon, 
  Video, List, CheckCircle, ChevronDown, ChevronUp, LayoutGrid
} from 'lucide-react';

interface AdminAreaProps {
  course: CourseConfig;
  onUpdate: (newData: CourseConfig) => void;
}

const AdminArea: React.FC<AdminAreaProps> = ({ course, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<'general' | 'modules' | 'appearance'>('modules');
  const [formData, setFormData] = useState<CourseConfig>(course);
  const [showSaveToast, setShowSaveToast] = useState(false);
  const [expandedModule, setExpandedModule] = useState<string | null>(formData.modules[0]?.id || null);

  const handleSave = () => {
    onUpdate(formData);
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const addModule = () => {
    const newModule: Module = {
      id: `mod-${Date.now()}`,
      title: 'Novo Módulo Premium',
      thumbnailUrl: 'https://images.unsplash.com/photo-1557683316-973673baf926?q=80&w=800&auto=format&fit=crop',
      lessons: []
    };
    setFormData(prev => ({ ...prev, modules: [...prev.modules, newModule] }));
    setExpandedModule(newModule.id);
  };

  const updateModule = (id: string, updates: Partial<Module>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === id ? { ...m, ...updates } : m)
    }));
  };

  const addLesson = (moduleId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          const modThumb = m.thumbnailUrl;
          return {
            ...m,
            lessons: [...m.lessons, {
              id: `les-${Date.now()}`,
              title: 'Nova Aula de Elite',
              thumbnailUrl: modThumb,
              videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ',
              description: 'Conteúdo programático...',
              duration: '15:00'
            }]
          };
        }
        return m;
      })
    }));
  };

  const updateLesson = (moduleId: string, lessonId: string, updates: Partial<Lesson>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: m.lessons.map(l => l.id === lessonId ? { ...l, ...updates } : l)
          };
        }
        return m;
      })
    }));
  };

  const deleteModule = (moduleId: string) => {
    setFormData(prev => ({ ...prev, modules: prev.modules.filter(m => m.id !== moduleId) }));
  };

  const deleteLesson = (moduleId: string, lessonId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return { ...m, lessons: m.lessons.filter(l => l.id !== lessonId) };
        }
        return m;
      })
    }));
  };

  return (
    <div className="max-w-7xl mx-auto p-10 bg-[#0a0a0a] min-h-screen">
      {showSaveToast && (
        <div className="fixed bottom-10 right-10 z-[200] animate-in fade-in slide-in-from-bottom-5 duration-300 bg-amber-500 text-black px-8 py-4 rounded-xl shadow-2xl flex items-center gap-3">
          <CheckCircle size={24} />
          <span className="font-black uppercase tracking-tight">Publicado com Sucesso!</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-12">
        <div>
          <h1 className="text-4xl font-black tracking-tighter uppercase italic">Painel do Produtor</h1>
          <p className="text-white/40 mt-2 font-medium">Personalize a experiência premium dos seus alunos.</p>
        </div>
        <button 
          onClick={handleSave}
          className="bg-amber-500 text-black px-12 py-4 rounded font-black hover:bg-white transition-all shadow-xl shadow-amber-500/10 flex items-center gap-3"
        >
          <Save size={20} /> SALVAR ALTERAÇÕES
        </button>
      </div>

      <div className="grid grid-cols-12 gap-12">
        <div className="col-span-12 lg:col-span-3 space-y-4">
          <button onClick={() => setActiveTab('general')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'general' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <LayoutIcon size={20} /> GERAL
          </button>
          <button onClick={() => setActiveTab('modules')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'modules' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <List size={20} /> CONTEÚDO
          </button>
          <button onClick={() => setActiveTab('appearance')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'appearance' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <ImageIcon size={20} /> VISUAL
          </button>
        </div>

        <div className="col-span-12 lg:col-span-9">
          {activeTab === 'general' && (
            <div className="bg-[#111] border border-white/5 rounded-2xl p-10 space-y-10">
               <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Layout dos Módulos (Área de Início)</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => setFormData({...formData, moduleLayout: 'horizontal'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleLayout === 'horizontal' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <LayoutGrid size={16} /> HORIZONTAL (GRID)
                    </button>
                    <button 
                      onClick={() => setFormData({...formData, moduleLayout: 'vertical'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleLayout === 'vertical' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <List size={16} /> VERTICAL (LISTA)
                    </button>
                  </div>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Nome do Treinamento</label>
                  <input type="text" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 focus:border-amber-500 outline-none" />
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Instrutor</label>
                  <input type="text" value={formData.instructorName} onChange={(e) => setFormData({...formData, instructorName: e.target.value})} className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 focus:border-amber-500 outline-none" />
                </div>
              </div>
              <div className="space-y-3">
                <label className="text-xs font-black text-white/40 uppercase tracking-widest">Link do Suporte Individual</label>
                <input type="text" value={formData.supportUrl} onChange={(e) => setFormData({...formData, supportUrl: e.target.value})} className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 focus:border-amber-500 outline-none" />
              </div>
            </div>
          )}

          {activeTab === 'modules' && (
            <div className="space-y-8">
              {formData.modules.map((mod, mIdx) => (
                <div key={mod.id} className="bg-[#111] border border-white/5 rounded-2xl overflow-hidden shadow-2xl">
                  <div onClick={() => setExpandedModule(expandedModule === mod.id ? null : mod.id)} className="p-6 flex items-center justify-between cursor-pointer hover:bg-white/5">
                    <div className="flex items-center gap-6">
                      <img src={mod.thumbnailUrl} className="w-24 h-14 rounded object-cover ring-1 ring-white/10" />
                      <div>
                        <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest mb-1 block">Módulo {mIdx + 1}</span>
                        <h3 className="text-xl font-bold">{mod.title}</h3>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <button onClick={(e) => { e.stopPropagation(); deleteModule(mod.id); }} className="p-3 text-white/20 hover:text-red-500">
                        <Trash2 size={20} />
                      </button>
                      {expandedModule === mod.id ? <ChevronUp className="text-white/20" /> : <ChevronDown className="text-white/20" />}
                    </div>
                  </div>

                  {expandedModule === mod.id && (
                    <div className="p-8 border-t border-white/5 space-y-8 bg-black/40">
                      <div className="grid grid-cols-2 gap-8">
                        <div className="space-y-3">
                          <label className="text-xs font-black text-white/40 uppercase tracking-widest">Título do Módulo</label>
                          <input type="text" value={mod.title} onChange={(e) => updateModule(mod.id, { title: e.target.value })} className="w-full bg-[#111] border border-white/10 rounded px-5 py-3 outline-none" />
