                        </div>
                      </div>

                      <div className="space-y-4">
                        <h4 className="text-sm font-bold flex items-center gap-3">Aulas do Módulo <span className="text-white/20">({mod.lessons.length})</span></h4>
                        <div className="space-y-6">
                          {mod.lessons.map((lesson) => (
                            <div key={lesson.id} className="p-6 bg-[#111] border border-white/5 rounded-xl space-y-6 shadow-inner">
                              <div className="flex items-center justify-between gap-4">
