                              </div>
                              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <div className="space-y-2">
                                  <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">URL Thumbnail Aula</label>
                                  <input 
                                    value={lesson.thumbnailUrl}
                                    onChange={(e) => updateLesson(mod.id, lesson.id, { thumbnailUrl: e.target.value })}
                                    className="w-full bg-black/50 border border-white/5 rounded px-4 py-2 text-[10px] outline-none"
                                  />
                                </div>
                                <div className="space-y-2">
                                  <label className="text-[10px] font-black text-white/30 uppercase tracking-widest">Link Embed</label>
                                  <input 
                                    value={lesson.videoUrl}
