                                  />
                                </div>
                              </div>
                            </div>
                          ))}
                          <button onClick={() => addLesson(mod.id)} className="w-full py-4 border-2 border-dashed border-white/5 rounded-xl text-white/20 font-bold hover:border-amber-500/30 hover:text-amber-500 transition-all flex items-center justify-center gap-2">
                            <Plus size={18} /> ADICIONAR NOVA AULA
