              <div className="w-full lg:w-80 space-y-6">
                <a 
                  href={course.supportUrl} 
                  target="_blank"
                  className="block w-full py-4 bg-white text-black text-center font-bold rounded-xl hover:bg-amber-500 transition-all shadow-lg"
