                                       onChange={(e) => updateLesson(mod.id, lesson.id, { thumbnailUrl: e.target.value })}
                                       className="bg-black/80 text-[8px] text-white/50 px-2 py-1 rounded w-full truncate border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity"
