                                    <div className="space-y-1">
                                      <label className="text-[10px] font-black text-white/20 uppercase tracking-widest flex items-center gap-1"><Video size={10} /> Embed URL</label>
                                      <input 
                                        value={lesson.videoUrl}
                                        onChange={(e) => updateLesson(mod.id, lesson.id, { videoUrl: e.target.value })}
                                        className="w-full bg-[#111] border border-white/10 rounded px-4 py-2 text-xs outline-none focus:border-amber-500"
                                      />
                                    </div>
                                    <div className="space-y-1">
                                      <label className="text-[10px] font-black text-white/20 uppercase tracking-widest flex items-center gap-1"><List size={10} /> Duração</label>
                                      <input 
                                        value={lesson.duration}
                                        onChange={(e) => updateLesson(mod.id, lesson.id, { duration: e.target.value })}
                                        className="w-full bg-[#111] border border-white/10 rounded px-4 py-2 text-xs outline-none focus:border-amber-500"
                                      />
                                    </div>
                                  </div>
                                </div>
                              </div>

