                                      <div className="bg-[#334155] rounded-t-xl p-2 flex flex-wrap gap-1 items-center border border-white/10">
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<pre><code>CODIGO AQUI</code></pre>')} title="HTML" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><Code size={16} /></button>
                                        <div className="w-[1px] h-4 bg-white/10 mx-1"></div>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<b>TEXTO EM NEGRITO</b>')} title="Negrito" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><Bold size={16} /></button>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<i>TEXTO EM ITALICO</i>')} title="Itálico" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><Italic size={16} /></button>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<strike>TEXTO RISCADO</strike>')} title="Riscado" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><Strikethrough size={16} /></button>
                                        <div className="w-[1px] h-4 bg-white/10 mx-1"></div>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<ul><li>Item 1</li><li>Item 2</li></ul>')} title="Lista Simples" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><ListIcon size={16} /></button>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<ol><li>Item 1</li><li>Item 2</li></ol>')} title="Lista Numerada" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><ListOrdered size={16} /></button>
                                        <div className="w-[1px] h-4 bg-white/10 mx-1"></div>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<img src="URL_DA_IMAGEM" alt="Descricao" />')} title="Imagem" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><ImageIcon size={16} /></button>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<a href="https://google.com" target="_blank">LINK AQUI</a>')} title="Link" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><LinkIcon size={16} /></button>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<hr />')} title="Divisor" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><Minus size={16} /></button>
                                        <div className="w-[1px] h-4 bg-white/10 mx-1"></div>
                                        {/* CUSTOM PREMIUM BUTTONS */}
                                        <button 
                                            onClick={() => insertHtmlAtCursor(mod.id, lesson.id, `<a href="${course.supportUrl}" target="_blank" class="btn-premium-support">SUPORTE VIA WHATSAPP</a>`)} 
                                            title="Botão WhatsApp Premium" 
                                            className="px-3 py-1 bg-amber-500/10 text-amber-500 rounded text-[10px] font-black border border-amber-500/20 flex items-center gap-1.5 hover:bg-amber-500 hover:text-black transition-all"
                                        >
                                            <MessageCircle size={10} /> BOTÃO WHATSAPP
                                        </button>
                                        <button 
                                            onClick={() => insertHtmlAtCursor(mod.id, lesson.id, `<a href="#" class="btn-premium-support">🚀 ACESSAR FERRAMENTA AGORA</a>`)} 
                                            title="Botão Rocket" 
                                            className="px-3 py-1 bg-indigo-500/10 text-indigo-400 rounded text-[10px] font-black border border-indigo-500/20 flex items-center gap-1.5 hover:bg-indigo-500 hover:text-white transition-all"
                                        >
                                            <Rocket size={10} /> BOTÃO DE ACESSO
                                        </button>
                                      </div>
                                      <textarea 
                                        value={lesson.description}
                                        onChange={(e) => updateLesson(mod.id, lesson.id, { description: e.target.value })}
                                        rows={10}
                                        className="w-full bg-white text-slate-900 border border-white/10 rounded-b-xl px-4 py-3 text-sm font-mono outline-none resize-none focus:border-amber-500"
                                        placeholder="Use HTML para formatar o conteúdo da aula..."
                                      />
                                      <p className="mt-2 text-[10px] text-white/20 font-medium">Este campo suporta HTML completo para você adicionar o que quiser (links, imagens, vídeos extras, botões personalizados).</p>
                                    </div>
                                  )}
                                </div>

                                <div className="border-t border-white/5">
                                  <button 
                                    onClick={() => toggleLessonSection(lesson.id, 'materials')}
                                    className="w-full py-4 flex items-center justify-between text-xs font-bold text-white/40 hover:text-white transition-colors"
                                  >
                                    <div className="flex items-center gap-3"><FilePlus size={14} /> MATERIAL EXTRA (ANEXOS)</div>
                                    {expandedLessonSections[lesson.id] === 'materials' ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                                  </button>
                                  {expandedLessonSections[lesson.id] === 'materials' && (
                                    <div className="pb-4 space-y-3 animate-in slide-in-from-top-2 duration-200">
                                      {lesson.materials.map((mat) => (
                                        <div key={mat.id} className="flex gap-4 items-center">
                                          <input 
                                            value={mat.name}
                                            onChange={(e) => updateMaterial(mod.id, lesson.id, mat.id, { name: e.target.value })}
                                            className="flex-1 bg-[#111] border border-white/10 rounded px-3 py-2 text-xs"
                                            placeholder="Nome do Material"
                                          />
                                          <input 
                                            value={mat.url}
                                            onChange={(e) => updateMaterial(mod.id, lesson.id, mat.id, { url: e.target.value })}
                                            className="flex-1 bg-[#111] border border-white/10 rounded px-3 py-2 text-xs"
                                            placeholder="URL do Arquivo"
                                          />
                                          <button onClick={() => deleteMaterial(mod.id, lesson.id, mat.id)} className="text-white/10 hover:text-red-500"><Trash2 size={14} /></button>
                                        </div>
                                      ))}
                                      <button 
                                        onClick={() => addMaterial(mod.id, lesson.id)}
                                        className="w-full py-2 border border-dashed border-white/10 rounded text-[10px] font-bold text-white/20 hover:text-amber-500 hover:border-amber-500/30 transition-all"
                                      >
                                        + ADICIONAR NOVO ANEXO
                                      </button>
                                    </div>
                                  )}
                                </div>

                                <div className="border-t border-white/5">
                                  <button 
                                    onClick={() => toggleLessonSection(lesson.id, 'release')}
                                    className="w-full py-4 flex items-center justify-between text-xs font-bold text-white/40 hover:text-white transition-colors"
                                  >
                                    <div className="flex items-center gap-3"><Calendar size={14} /> LIBERAÇÃO E EXPIRAÇÃO</div>
                                    {expandedLessonSections[lesson.id] === 'release' ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                                  </button>
                                  {expandedLessonSections[lesson.id] === 'release' && (
                                    <div className="pb-4 animate-in slide-in-from-top-2 duration-200">
                                      <div className="flex items-center gap-4">
                                        <span className="text-xs text-white/40">Liberar após</span>
                                        <input 
                                          type="number"
                                          value={lesson.releaseDays}
                                          onChange={(e) => updateLesson(mod.id, lesson.id, { releaseDays: parseInt(e.target.value) || 0 })}
                                          className="w-20 bg-[#111] border border-white/10 rounded px-3 py-2 text-xs font-bold text-amber-500"
                                        />
                                        <span className="text-xs text-white/40 font-bold uppercase tracking-widest italic">DIAS DA COMPRA</span>
                                      </div>
                                    </div>
                                  )}
                                </div>

                                <div className="border-t border-white/5">
                                  <button 
                                    onClick={() => toggleLessonSection(lesson.id, 'tags')}
                                    className="w-full py-4 flex items-center justify-between text-xs font-bold text-white/40 hover:text-white transition-colors"
                                  >
                                    <div className="flex items-center gap-3"><Tag size={14} /> TAGS DE BUSCA</div>
                                    {expandedLessonSections[lesson.id] === 'tags' ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                                  </button>
                                  {expandedLessonSections[lesson.id] === 'tags' && (
                                    <div className="pb-4 animate-in slide-in-from-top-2 duration-200">
                                      <input 
                                        value={lesson.tags}
                                        onChange={(e) => updateLesson(mod.id, lesson.id, { tags: e.target.value })}
                                        className="w-full bg-[#111] border border-white/10 rounded px-4 py-2 text-xs italic"
                                        placeholder="Separe as tags por vírgula"
                                      />
                                    </div>
                                  )}
                                </div>
                              </div>
                            </div>
                          ))}
                          <button onClick={() => addLesson(mod.id)} className="w-full py-6 border-2 border-dashed border-white/5 rounded-2xl text-white/20 font-black uppercase tracking-widest hover:border-amber-500/30 hover:text-amber-500 transition-all flex items-center justify-center gap-2 italic">
                            <Plus size={24} /> Criar Nova Aula de Elite
                          </button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              ))}
              <button onClick={addModule} className="w-full py-10 bg-white text-black font-black uppercase tracking-tighter rounded-2xl shadow-2xl hover:bg-amber-500 transition-all flex items-center justify-center gap-4 text-2xl italic">
                <Plus size={32} /> Criar Novo Módulo
              </button>
            </div>
          )}

          {activeTab === 'appearance' && (
            <div className="bg-[#111] border border-white/5 rounded-2xl p-10 space-y-12">
              <div className="space-y-6">
                <h3 className="text-xl font-bold border-l-4 border-amber-500 pl-4">Identidade Visual</h3>
                <div className="grid grid-cols-2 gap-10">
                  <div className="space-y-4">
                    <label className="text-xs font-black text-white/40 uppercase tracking-widest">Logo Principal (PNG/SVG)</label>
                    <div className="flex gap-6">
                      <img src={formData.logoUrl} className="w-20 h-20 rounded bg-white/5 p-2 object-contain" />
                      <input type="text" value={formData.logoUrl} onChange={(e) => setFormData({...formData, logoUrl: e.target.value})} className="flex-1 bg-black border border-white/10 rounded px-5 outline-none text-xs" />
                    </div>
                  </div>
                  <div className="space-y-4">
                    <label className="text-xs font-black text-white/40 uppercase tracking-widest">Cor de Destaque</label>
                    <div className="flex gap-6 items-center">
                      <input type="color" value={formData.accentColor} onChange={(e) => setFormData({...formData, accentColor: e.target.value})} className="w-14 h-14 bg-transparent border-none cursor-pointer" />
                      <input type="text" value={formData.accentColor} className="flex-1 bg-black border border-white/10 rounded px-5 py-3 outline-none text-xs font-mono" readOnly />
                    </div>
                  </div>
                </div>
              </div>

              <div className="space-y-6 pt-10 border-t border-white/5">
                <h3 className="text-xl font-bold border-l-4 border-amber-500 pl-4">Capa Cinematográfica</h3>
                <div className="space-y-4">
                  <div className="w-full aspect-[21/9] rounded-2xl overflow-hidden ring-1 ring-white/10">
                    <img src={formData.bannerUrl} className="w-full h-full object-cover" />
                  </div>
                  <input type="text" value={formData.bannerUrl} onChange={(e) => setFormData({...formData, bannerUrl: e.target.value})} placeholder="URL da Imagem 4K para o Banner" className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 outline-none focus:border-amber-500" />
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminArea;

import React, { useState, useRef } from 'react';
import { CourseConfig, Module, Lesson, Material } from '../types';
import { 
  Save, Plus, Trash2, Edit3, Image as ImageIcon, Layout as LayoutIcon, 
  Video, List, CheckCircle, ChevronDown, ChevronUp, LayoutGrid, Square, RectangleHorizontal, 
  FilePlus, Calendar, Tag, Info, Code, Bold, Italic, Strikethrough, ListOrdered, ListIcon, 
  Link as LinkIcon, Minus, Type, MessageCircle, Rocket, Upload, FileText, X
} from 'lucide-react';

interface AdminAreaProps {
  course: CourseConfig;
  onUpdate: (newData: CourseConfig) => void;
}

const AdminArea: React.FC<AdminAreaProps> = ({ course, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<'general' | 'modules' | 'appearance'>('modules');
  const [formData, setFormData] = useState<CourseConfig>(course);
  const [showSaveToast, setShowSaveToast] = useState(false);
  const [expandedModule, setExpandedModule] = useState<string | null>(formData.modules[0]?.id || null);
  const [expandedLessonSections, setExpandedLessonSections] = useState<Record<string, string | null>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currentUploadTarget = useRef<{ modId: string, lessonId: string } | null>(null);

  const handleSave = () => {
    onUpdate(formData);
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const toggleLessonSection = (lessonId: string, section: string) => {
    setExpandedLessonSections(prev => ({
      ...prev,
      [lessonId]: prev[lessonId] === section ? null : section
    }));
  };

  const insertHtmlAtCursor = (moduleId: string, lessonId: string, htmlToInsert: string) => {
    const lesson = formData.modules.find(m => m.id === moduleId)?.lessons.find(l => l.id === lessonId);
    if (!lesson) return;
    const currentDescription = lesson.description || '';
    updateLesson(moduleId, lessonId, { description: currentDescription + '\n' + htmlToInsert });
  };

  const addModule = () => {
    const newModule: Module = {
      id: `mod-${Date.now()}`,
      title: 'Novo Módulo Premium',
      thumbnailUrl: 'https://images.unsplash.com/photo-1557683316-973673baf926?q=80&w=800&auto=format&fit=crop',
      lessons: []
    };
    setFormData(prev => ({ ...prev, modules: [...prev.modules, newModule] }));
    setExpandedModule(newModule.id);
  };

  const updateModule = (id: string, updates: Partial<Module>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === id ? { ...m, ...updates } : m)
    }));
  };

  const addLesson = (moduleId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          const modThumb = m.thumbnailUrl;
          return {
            ...m,
            lessons: [...m.lessons, {
              id: `les-${Date.now()}`,
              title: 'Nova Aula de Elite',
              thumbnailUrl: modThumb,
              videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ',
              description: '<p>Conteúdo programático...</p>',
              duration: '15:00',
              materials: [],
              tags: '',
              releaseDays: 0
            }]
          };
        }
        return m;
      })
    }));
  };

  const updateLesson = (moduleId: string, lessonId: string, updates: Partial<Lesson>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: m.lessons.map(l => l.id === lessonId ? { ...l, ...updates } : l)
          };
        }
        return m;
      })
    }));
  };

  const triggerFileUpload = (modId: string, lessonId: string) => {
    currentUploadTarget.current = { modId, lessonId };
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    const target = currentUploadTarget.current;
    if (!files || !target) return;

    const mod = formData.modules.find(m => m.id === target.modId);
    const lesson = mod?.lessons.find(l => l.id === target.lessonId);
    if (!lesson) return;

    const allowedExtensions = ['jpg', 'jpeg', 'gif', 'png', 'bmp', 'pdf', 'zip', 'rar', 'epub', 'xls', 'xlsx', 'xlsm', 'mp3', 'doc', 'docx', 'ppt', 'pptx'];
    const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB
    const MAX_FILES = 10;

    const currentFilesCount = lesson.materials?.length || 0;
    const remainingSlots = MAX_FILES - currentFilesCount;

    if (remainingSlots <= 0) {
      alert(`Você já atingiu o limite de ${MAX_FILES} arquivos para esta aula.`);
      return;
    }

    const newMaterials: Material[] = [];
    const filesArray = Array.from(files).slice(0, remainingSlots);

    filesArray.forEach(file => {
      const extension = file.name.split('.').pop()?.toLowerCase();
      if (!extension || !allowedExtensions.includes(extension)) {
        alert(`Formato de arquivo não permitido: ${file.name}`);
        return;
      }
      if (file.size > MAX_FILE_SIZE) {
        alert(`O arquivo ${file.name} excede o limite de 100MB.`);
        return;
      }

      // In a real app, you'd upload this to a server. 
      // For this demo, we use URL.createObjectURL or a mock URL.
      const fileUrl = URL.createObjectURL(file);
      newMaterials.push({
        id: `mat-${Date.now()}-${Math.random()}`,
        name: file.name,
        url: fileUrl
      });
    });

    if (newMaterials.length > 0) {
      setFormData(prev => ({
        ...prev,
        modules: prev.modules.map(m => m.id === target.modId ? {
          ...m,
          lessons: m.lessons.map(l => l.id === target.lessonId ? { 
            ...l, 
            materials: [...(l.materials || []), ...newMaterials] 
          } : l)
        } : m)
      }));
    }

    // Reset input
    e.target.value = '';
    currentUploadTarget.current = null;
  };

  const deleteMaterial = (modId: string, lessonId: string, matId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === modId ? {
        ...m,
        lessons: m.lessons.map(l => l.id === lessonId ? {
          ...l,
          materials: l.materials.filter(mat => mat.id !== matId)
        } : l)
      } : m)
    }));
  };

  const deleteModule = (moduleId: string) => {
    setFormData(prev => ({ ...prev, modules: prev.modules.filter(m => m.id !== moduleId) }));
  };

  const deleteLesson = (moduleId: string, lessonId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return { ...m, lessons: m.lessons.filter(l => l.id !== lessonId) };
        }
        return m;
      })
    }));
  };

  return (
    <div className="max-w-7xl mx-auto p-10 bg-[#0a0a0a] min-h-screen">
      {/* Hidden File Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        className="hidden" 
        multiple
        accept=".jpg,.jpeg,.gif,.png,.bmp,.pdf,.zip,.rar,.epub,.xls,.xlsx,.xlsm,.mp3,.doc,.docx,.ppt,.pptx"
      />

      {showSaveToast && (
        <div className="fixed bottom-10 right-10 z-[200] animate-in fade-in slide-in-from-bottom-5 duration-300 bg-amber-500 text-black px-8 py-4 rounded-xl shadow-2xl flex items-center gap-3">
          <CheckCircle size={24} />
          <span className="font-black uppercase tracking-tight">Publicado com Sucesso!</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-12">
        <div>
          <h1 className="text-4xl font-black tracking-tighter uppercase italic text-white">Painel do Produtor</h1>
          <p className="text-white/40 mt-2 font-medium">Personalize a experiência premium dos seus alunos.</p>
        </div>
        <button 
          onClick={handleSave}
          className="bg-amber-500 text-black px-12 py-4 rounded font-black hover:bg-white transition-all shadow-xl shadow-amber-500/10 flex items-center gap-3"
        >
          <Save size={20} /> SALVAR ALTERAÇÕES
        </button>
      </div>

      <div className="grid grid-cols-12 gap-12">
        <div className="col-span-12 lg:col-span-3 space-y-4">
          <button onClick={() => setActiveTab('general')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'general' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <LayoutIcon size={20} /> GERAL
          </button>
          <button onClick={() => setActiveTab('modules')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'modules' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <List size={20} /> CONTEÚDO
          </button>
          <button onClick={() => setActiveTab('appearance')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'appearance' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <ImageIcon size={20} /> VISUAL
          </button>
        </div>

        <div className="col-span-12 lg:col-span-9">
          {activeTab === 'general' && (
            <div className="bg-[#111] border border-white/5 rounded-2xl p-10 space-y-10">
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Orientação da Thumbnail do Módulo</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => setFormData({...formData, moduleThumbnailOrientation: 'horizontal'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleThumbnailOrientation === 'horizontal' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <RectangleHorizontal size={16} /> HORIZONTAL (16:9)
                    </button>
                    <button 
                      onClick={() => setFormData({...formData, moduleThumbnailOrientation: 'vertical'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleThumbnailOrientation === 'vertical' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <Square size={16} /> VERTICAL (2:3)
                    </button>
                  </div>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Nome do Treinamento</label>
                  <input type="text" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 text-white focus:border-amber-500 outline-none" />
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Instrutor</label>
                  <input type="text" value={formData.instructorName} onChange={(e) => setFormData({...formData, instructorName: e.target.value})} className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 text-white focus:border-amber-500 outline-none" />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'modules' && (
            <div className="space-y-8">
              {formData.modules.map((mod, mIdx) => (
                <div key={mod.id} className="bg-[#111] border border-white/5 rounded-2xl overflow-hidden shadow-2xl">
                  <div onClick={() => setExpandedModule(expandedModule === mod.id ? null : mod.id)} className="p-6 flex items-center justify-between cursor-pointer hover:bg-white/5">
                    <div className="flex items-center gap-6">
                      <div className={`rounded object-cover ring-1 ring-white/10 overflow-hidden ${formData.moduleThumbnailOrientation === 'horizontal' ? 'w-24 h-14' : 'w-10 h-14'}`}>
                        <img src={mod.thumbnailUrl} className="w-full h-full object-cover" />
                      </div>
                      <div>
