                        className="bg-white text-black px-8 py-3 rounded-xl font-black flex items-center gap-3 hover:bg-amber-500 transition-all shadow-2xl"
                      >
                        <Upload size={20} /> ALTERAR IMAGEM DE CAPA
                      </button>
