import React, { useState, useRef } from 'react';
import { CourseConfig, Module, Lesson, Material } from '../types';
import { 
  Save, Plus, Trash2, Edit3, Image as ImageIcon, Layout as LayoutIcon, 
  Video, List, CheckCircle, ChevronDown, ChevronUp, LayoutGrid, Square, RectangleHorizontal, 
  FilePlus, Calendar, Tag, Info, Code, Bold, Italic, Strikethrough, ListOrdered, ListIcon, 
  Link as LinkIcon, Minus, Type, MessageCircle, Rocket, Upload, FileText, X, Settings2
} from 'lucide-react';

interface AdminAreaProps {
  course: CourseConfig;
  onUpdate: (newData: CourseConfig) => void;
}

const AdminArea: React.FC<AdminAreaProps> = ({ course, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<'general' | 'modules' | 'appearance'>('modules');
  const [formData, setFormData] = useState<CourseConfig>(course);
  const [showSaveToast, setShowSaveToast] = useState(false);
  const [expandedModule, setExpandedModule] = useState<string | null>(formData.modules[0]?.id || null);
  const [expandedLessonSections, setExpandedLessonSections] = useState<Record<string, string | null>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const currentUploadTarget = useRef<{ modId: string, lessonId: string } | null>(null);
  const currentImageTarget = useRef<{ type: 'logo' | 'banner' | 'module' | 'lesson', modId?: string, lessonId?: string } | null>(null);

  const handleSave = () => {
    onUpdate(formData);
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const toggleLessonSection = (lessonId: string, section: string) => {
    setExpandedLessonSections(prev => ({
      ...prev,
      [lessonId]: prev[lessonId] === section ? null : section
    }));
  };

  const insertHtmlAtCursor = (moduleId: string, lessonId: string, htmlToInsert: string) => {
    const lesson = formData.modules.find(m => m.id === moduleId)?.lessons.find(l => l.id === lessonId);
    if (!lesson) return;
    const currentDescription = lesson.description || '';
    updateLesson(moduleId, lessonId, { description: currentDescription + '\n' + htmlToInsert });
  };

  const addModule = () => {
    const newModule: Module = {
      id: `mod-${Date.now()}`,
      title: 'Novo Módulo Premium',
      thumbnailUrl: 'https://images.unsplash.com/photo-1557683316-973673baf926?q=80&w=800&auto=format&fit=crop',
      lessons: []
    };
    setFormData(prev => ({ ...prev, modules: [...prev.modules, newModule] }));
    setExpandedModule(newModule.id);
  };

  const updateModule = (id: string, updates: Partial<Module>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === id ? { ...m, ...updates } : m)
    }));
  };

  const addLesson = (moduleId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          const modThumb = m.thumbnailUrl;
          return {
            ...m,
            lessons: [...m.lessons, {
              id: `les-${Date.now()}`,
              title: 'Nova Aula de Elite',
              thumbnailUrl: modThumb,
              videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ',
              description: '<p>Conteúdo programático...</p>',
              materials: [],
              tags: '',
              releaseDays: 0
            }]
          };
        }
        return m;
      })
    }));
  };

  const updateLesson = (moduleId: string, lessonId: string, updates: Partial<Lesson>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: m.lessons.map(l => l.id === lessonId ? { ...l, ...updates } : l)
          };
        }
        return m;
      })
    }));
  };

  const triggerFileUpload = (modId: string, lessonId: string) => {
    currentUploadTarget.current = { modId, lessonId };
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const triggerImageUpload = (target: typeof currentImageTarget.current) => {
    currentImageTarget.current = target;
    if (imageInputRef.current) {
      imageInputRef.current.click();
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    const target = currentImageTarget.current;
    if (!file || !target) return;

    const allowedExtensions = ['jpg', 'jpeg', 'png', 'webp', 'gif', 'svg'];
    const extension = file.name.split('.').pop()?.toLowerCase();

    if (!extension || !allowedExtensions.includes(extension)) {
      alert('Por favor, selecione uma imagem válida (JPG, PNG, WEBP, GIF ou SVG).');
      return;
    }

    const imageUrl = URL.createObjectURL(file);

    if (target.type === 'logo') {
      setFormData(prev => ({ ...prev, logoUrl: imageUrl }));
    } else if (target.type === 'banner') {
      setFormData(prev => ({ ...prev, bannerUrl: imageUrl }));
    } else if (target.type === 'module' && target.modId) {
      updateModule(target.modId, { thumbnailUrl: imageUrl });
    } else if (target.type === 'lesson' && target.modId && target.lessonId) {
      updateLesson(target.modId, target.lessonId, { thumbnailUrl: imageUrl });
    }

    e.target.value = '';
    currentImageTarget.current = null;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    const target = currentUploadTarget.current;
    if (!files || !target) return;

    const mod = formData.modules.find(m => m.id === target.modId);
    const lesson = mod?.lessons.find(l => l.id === target.lessonId);
    if (!lesson) return;

    const allowedExtensions = ['jpg', 'jpeg', 'gif', 'png', 'bmp', 'pdf', 'zip', 'rar', 'epub', 'xls', 'xlsx', 'xlsm', 'mp3', 'doc', 'docx', 'ppt', 'pptx'];
    const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB
    const MAX_FILES = 10;

    const currentFilesCount = lesson.materials?.length || 0;
    const remainingSlots = MAX_FILES - currentFilesCount;

    if (remainingSlots <= 0) {
      alert(`Você já atingiu o limite de ${MAX_FILES} arquivos para esta aula.`);
      return;
    }

    const newMaterials: Material[] = [];
    const filesArray = Array.from(files).slice(0, remainingSlots);

    filesArray.forEach(file => {
      const extension = file.name.split('.').pop()?.toLowerCase();
      if (!extension || !allowedExtensions.includes(extension)) {
        alert(`Formato de arquivo não permitido: ${file.name}`);
        return;
      }
      if (file.size > MAX_FILE_SIZE) {
        alert(`O arquivo ${file.name} excede o limite de 100MB.`);
        return;
      }

      const fileUrl = URL.createObjectURL(file);
      newMaterials.push({
        id: `mat-${Date.now()}-${Math.random()}`,
        name: file.name,
        url: fileUrl
      });
    });

    if (newMaterials.length > 0) {
      setFormData(prev => ({
        ...prev,
        modules: prev.modules.map(m => m.id === target.modId ? {
          ...m,
          lessons: m.lessons.map(l => l.id === target.lessonId ? { 
            ...l, 
            materials: [...(l.materials || []), ...newMaterials] 
          } : l)
        } : m)
      }));
    }

    e.target.value = '';
    currentUploadTarget.current = null;
  };

  const updateMaterial = (modId: string, lessonId: string, matId: string, updates: Partial<Material>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === modId ? {
        ...m,
        lessons: m.lessons.map(l => l.id === lessonId ? {
          ...l,
          materials: l.materials.map(mat => mat.id === matId ? { ...mat, ...updates } : mat)
        } : l)
      } : m)
    }));
  };

  const deleteMaterial = (modId: string, lessonId: string, matId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === modId ? {
        ...m,
        lessons: m.lessons.map(l => l.id === lessonId ? {
          ...l,
          materials: l.materials.filter(mat => mat.id !== matId)
        } : l)
      } : m)
    }));
  };

  const deleteModule = (moduleId: string) => {
    setFormData(prev => ({ ...prev, modules: prev.modules.filter(m => m.id !== moduleId) }));
  };

  const deleteLesson = (moduleId: string, lessonId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return { ...m, lessons: m.lessons.filter(l => l.id !== lessonId) };
        }
        return m;
      })
    }));
  };

  return (
    <div className="max-w-7xl mx-auto p-10 bg-[#0a0a0a] min-h-screen">
      {/* Hidden File Input for Materials */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        className="hidden" 
        multiple
        accept=".jpg,.jpeg,.gif,.png,.bmp,.pdf,.zip,.rar,.epub,.xls,.xlsx,.xlsm,.mp3,.doc,.docx,.ppt,.pptx"
      />

      {/* Hidden File Input for Images (Logo, Banner, Thumbs) */}
      <input 
        type="file" 
        ref={imageInputRef} 
        onChange={handleImageChange} 
        className="hidden" 
        accept="image/*"
      />

      {showSaveToast && (
        <div className="fixed bottom-10 right-10 z-[200] animate-in fade-in slide-in-from-bottom-5 duration-300 bg-amber-500 text-black px-8 py-4 rounded-xl shadow-2xl flex items-center gap-3">
          <CheckCircle size={24} />
          <span className="font-black uppercase tracking-tight">Publicado com Sucesso!</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-12">
        <div>
          <h1 className="text-4xl font-black tracking-tighter uppercase italic text-white">Painel do Produtor</h1>
          <p className="text-white/40 mt-2 font-medium">Personalize a experiência premium dos seus alunos.</p>
        </div>
        <button 
          onClick={handleSave}
          className="bg-amber-500 text-black px-12 py-4 rounded font-black hover:bg-white transition-all shadow-xl shadow-amber-500/10 flex items-center gap-3"
        >
          <Save size={20} /> SALVAR ALTERAÇÕES
        </button>
      </div>

      <div className="grid grid-cols-12 gap-12">
        <div className="col-span-12 lg:col-span-3 space-y-4">
          <button onClick={() => setActiveTab('general')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'general' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <LayoutIcon size={20} /> GERAL
          </button>
          <button onClick={() => setActiveTab('modules')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'modules' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <List size={20} /> CONTEÚDO
          </button>
          <button onClick={() => setActiveTab('appearance')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'appearance' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <ImageIcon size={20} /> VISUAL
          </button>
        </div>

        <div className="col-span-12 lg:col-span-9">
          {activeTab === 'general' && (
            <div className="bg-[#111] border border-white/5 rounded-2xl p-10 space-y-10">
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Orientação da Thumbnail do Módulo</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => setFormData({...formData, moduleThumbnailOrientation: 'horizontal'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleThumbnailOrientation === 'horizontal' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <RectangleHorizontal size={16} /> HORIZONTAL (16:9)
                    </button>
                    <button 
                      onClick={() => setFormData({...formData, moduleThumbnailOrientation: 'vertical'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleThumbnailOrientation === 'vertical' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <Square size={16} /> VERTICAL (2:3)
                    </button>
                  </div>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Nome do Treinamento</label>
                  <input type="text" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 text-white focus:border-amber-500 outline-none" />
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Instrutor</label>
                  <input type="text" value={formData.instructorName} onChange={(e) => setFormData({...formData, instructorName: e.target.value})} className="w-full bg-black border border-white/10 rounded-lg px-5 py-4 text-white focus:border-amber-500 outline-none" />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'modules' && (
            <div className="space-y-8">
              {formData.modules.map((mod, mIdx) => (
                <div key={mod.id} className="bg-[#111] border border-white/5 rounded-2xl overflow-hidden shadow-2xl">
                  {/* MODULE HEADER BAR */}
                  <div onClick={() => setExpandedModule(expandedModule === mod.id ? null : mod.id)} className="p-6 flex items-center justify-between cursor-pointer hover:bg-white/5 bg-black/20">
                    <div className="flex items-center gap-6">
                      <div className={`rounded object-cover ring-1 ring-white/10 overflow-hidden ${formData.moduleThumbnailOrientation === 'horizontal' ? 'w-24 h-14' : 'w-10 h-14'}`}>
                        <img src={mod.thumbnailUrl} className="w-full h-full object-cover" alt={mod.title} />
                      </div>
                      <div>
                        <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest mb-1 block">Módulo {mIdx + 1}</span>
                        <h3 className="text-xl font-bold text-white">{mod.title}</h3>
                      </div>
                    </div>
                    <div className="flex items-center gap-4">
                      <button onClick={(e) => { e.stopPropagation(); deleteModule(mod.id); }} className="p-3 text-white/20 hover:text-red-500 transition-colors">
                        <Trash2 size={20} />
                      </button>
                      {expandedModule === mod.id ? <ChevronUp className="text-white/20" /> : <ChevronDown className="text-white/20" />}
                    </div>
                  </div>

                  {expandedModule === mod.id && (
                    <div className="animate-in slide-in-from-top-4 duration-300">
                      {/* MODULE SETTINGS SECTION */}
                      <div className="p-8 border-t border-white/5 bg-white/[0.02] space-y-6">
                        <div className="flex items-center gap-3 mb-4">
                          <Settings2 size={16} className="text-amber-500" />
                          <h4 className="text-xs font-black uppercase tracking-[0.2em] text-white/40 italic">Configurações do Módulo</h4>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                          <div className="space-y-3">
                            <label className="text-[10px] font-black text-white/20 uppercase tracking-widest">Título do Módulo</label>
                            <input type="text" value={mod.title} onChange={(e) => updateModule(mod.id, { title: e.target.value })} className="w-full bg-black/40 border border-white/10 text-white rounded px-5 py-3 outline-none focus:border-amber-500 transition-colors" />
                          </div>
                          <div className="space-y-3">
                            <label className="text-[10px] font-black text-white/20 uppercase tracking-widest">Capa do Módulo (Thumbnail)</label>
                            <div className="flex gap-4">
                              <input 
                                type="text" 
                                value={mod.thumbnailUrl} 
                                onChange={(e) => updateModule(mod.id, { thumbnailUrl: e.target.value })} 
                                className="flex-1 bg-black/40 border border-white/10 text-white rounded px-5 py-3 outline-none text-xs truncate" 
                                placeholder="URL da Imagem"
                              />
                              <button 
                                onClick={() => triggerImageUpload({ type: 'module', modId: mod.id })}
                                className="bg-amber-500 text-black px-6 rounded font-black text-xs flex items-center gap-2 hover:bg-white transition-all shadow-lg whitespace-nowrap"
                              >
                                <Upload size={14} /> UPLOAD
                              </button>
                            </div>
                          </div>
                        </div>
                      </div>

                      {/* LESSONS LIST SECTION */}
                      <div className="p-8 border-t border-white/5 bg-black/40 space-y-8">
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-3">
                            <List size={16} className="text-amber-500" />
                            <h4 className="text-xs font-black uppercase tracking-[0.2em] text-white/40 italic">Conteúdo (Aulas)</h4>
                          </div>
                          <span className="text-[10px] font-black text-white/20 uppercase tracking-widest">{mod.lessons.length} aulas cadastradas</span>
                        </div>

                        <div className="space-y-6">
                          {mod.lessons.map((lesson) => (
                            <div key={lesson.id} className="bg-[#111] border border-white/5 rounded-2xl overflow-hidden shadow-xl ring-1 ring-white/5">
                              <div className="p-6 flex flex-col md:flex-row gap-6">
                                <div className="w-full md:w-56 aspect-video rounded-xl bg-black overflow-hidden relative group border border-white/10">
                                  <img src={lesson.thumbnailUrl} className="w-full h-full object-cover opacity-60 group-hover:opacity-100 transition-opacity" alt={lesson.title} />
                                  <div className="absolute inset-0 flex items-center justify-center p-2 opacity-0 group-hover:opacity-100 transition-all duration-300">
                                     <button 
                                      onClick={() => triggerImageUpload({ type: 'lesson', modId: mod.id, lessonId: lesson.id })}
                                      className="bg-black/80 text-white border border-white/20 px-3 py-1.5 rounded-lg text-[10px] font-black hover:bg-amber-500 hover:text-black transition-all flex items-center gap-2"
                                     >
                                       <Upload size={12} /> TROCAR CAPA
                                     </button>
                                  </div>
                                </div>
                                <div className="flex-1 space-y-4">
                                  <div className="flex items-center justify-between">
                                    <input 
                                      value={lesson.title}
                                      onChange={(e) => updateLesson(mod.id, lesson.id, { title: e.target.value })}
                                      className="bg-transparent text-xl font-black text-white italic outline-none border-b border-transparent focus:border-amber-500 w-full"
                                      placeholder="Título da Aula Completa"
                                    />
                                    <button onClick={() => deleteLesson(mod.id, lesson.id)} className="p-2 text-white/10 hover:text-red-500 transition-colors">
                                      <Trash2 size={20} />
                                    </button>
                                  </div>
                                  <div className="grid grid-cols-1 gap-4">
                                    <div className="space-y-1">
                                      <label className="text-[10px] font-black text-white/20 uppercase tracking-widest flex items-center gap-1"><Video size={10} /> Embed URL da Videoaula</label>
                                      <input 
                                        value={lesson.videoUrl}
                                        onChange={(e) => updateLesson(mod.id, lesson.id, { videoUrl: e.target.value })}
                                        className="w-full bg-black/40 border border-white/10 text-white rounded px-4 py-2 text-xs outline-none focus:border-amber-500"
                                        placeholder="URL do Vídeo (YouTube, Vimeo, etc.)"
                                      />
                                    </div>
                                  </div>
                                </div>
                              </div>

                              {/* ACCORDION SECTIONS FOR LESSON DETAILS */}
                              <div className="px-6 pb-6 space-y-2">
                                <div className="border-t border-white/5">
                                  <button 
                                    onClick={() => toggleLessonSection(lesson.id, 'description')}
                                    className="w-full py-4 flex items-center justify-between text-xs font-bold text-white/40 hover:text-white transition-colors"
                                  >
                                    <div className="flex items-center gap-3 font-black text-white/60 uppercase italic"><Type size={14} /> Descrição e Conteúdo Rico</div>
                                    {expandedLessonSections[lesson.id] === 'description' ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                                  </button>
                                  {expandedLessonSections[lesson.id] === 'description' && (
                                    <div className="pb-6 animate-in slide-in-from-top-2 duration-200">
                                      <div className="bg-[#334155] rounded-t-xl p-2 flex flex-wrap gap-1 items-center border border-white/10">
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<pre><code>CODIGO AQUI</code></pre>')} title="HTML" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><Code size={16} /></button>
                                        <div className="w-[1px] h-4 bg-white/10 mx-1"></div>
                                        <button onClick={() => insertHtmlAtCursor(mod.id, lesson.id, '<b>TEXTO EM NEGRITO</b>')} title="Negrito" className="p-1.5 hover:bg-white/10 rounded text-white/80 transition-colors"><Bold size={16} /></button>
