                          <button onClick={() => addLesson(mod.id)} className="w-full py-8 border-2 border-dashed border-white/5 rounded-2xl text-white/20 font-black uppercase tracking-widest hover:border-amber-500/30 hover:text-amber-500 transition-all flex items-center justify-center gap-3 italic">
