              ))}
              <button onClick={addModule} className="w-full py-12 bg-white text-black font-black uppercase tracking-tighter rounded-3xl shadow-2xl hover:bg-amber-500 transition-all flex items-center justify-center gap-4 text-2xl italic">
                <Plus size={32} /> CRIAR NOVO MÓDULO CONTAINER
              </button>
            </div>
