import React, { useState } from 'react';
import { CourseConfig, Lesson, Module, StudentView } from '../types';
import { Play, Search, Bell, Menu, Headphones, ChevronRight, ChevronLeft, Download, Tag, Calendar, Layout } from 'lucide-react';

interface StudentAreaProps {
  course: CourseConfig;
}

const StudentArea: React.FC<StudentAreaProps> = ({ course }) => {
  const [viewState, setViewState] = useState<StudentView>('home');
  const [selectedModule, setSelectedModule] = useState<Module>(course.modules[0]);
  const [selectedLesson, setSelectedLesson] = useState<Lesson>(course.modules[0]?.lessons[0]);

  const enterLesson = (mod: Module, lesson?: Lesson) => {
    if (!mod.lessons || mod.lessons.length === 0) {
      alert("Este módulo ainda não possui aulas cadastradas.");
      return;
    }
    setSelectedModule(mod);
    setSelectedLesson(lesson || mod.lessons[0]);
    setViewState('player');
  };

  if (viewState === 'player') {
    return (
      <div className="flex h-full overflow-hidden bg-[#0a0a0a]">
        {/* PLAYER SIDEBAR */}
        <aside className="w-80 bg-[#111] border-r border-white/5 flex flex-col hidden lg:flex">
          <div className="p-6 border-b border-white/5">
            <button 
              onClick={() => setViewState('home')}
              className="text-xs font-bold text-white/40 hover:text-white uppercase tracking-widest flex items-center gap-2 mb-4"
            >
              <ChevronLeft size={14} /> Voltar ao Início
            </button>
            <h2 className="font-bold text-lg leading-tight uppercase italic">{course.name}</h2>
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar">
            {course.modules.map((mod, mIdx) => (
              <div key={mod.id}>
                <div className="px-6 py-4 bg-white/5 text-[10px] font-black uppercase tracking-widest text-white/40 flex items-center gap-2">
                  <Layout size={10} className="text-amber-500" />
                  Módulo {mIdx + 1}: {mod.title}
                </div>
                {mod.lessons.map((lesson) => (
                  <button
                    key={lesson.id}
                    onClick={() => {
                      setSelectedModule(mod);
                      setSelectedLesson(lesson);
                    }}
                    className={`w-full px-6 py-4 text-left hover:bg-white/5 transition-all group border-l-4 ${
                      selectedLesson?.id === lesson.id ? 'bg-white/5 border-amber-500' : 'border-transparent'
                    }`}
                  >
                    <p className={`text-sm font-medium ${selectedLesson?.id === lesson.id ? 'text-amber-500' : 'text-white/70'}`}>
                      {lesson.title}
                    </p>
                  </button>
                ))}
              </div>
            ))}
          </div>
        </aside>

        {/* PLAYER CONTENT AREA */}
        <main className="flex-1 overflow-y-auto custom-scrollbar pb-20">
          <div className="max-w-5xl mx-auto p-4 lg:p-10">
            {selectedLesson ? (
              <>
                <div className="aspect-video bg-black rounded-2xl overflow-hidden shadow-2xl mb-10 ring-1 ring-white/10 shadow-amber-500/5">
                  <iframe
                    src={selectedLesson.videoUrl}
                    className="w-full h-full"
                    allowFullScreen
                    title={selectedLesson.title}
                  ></iframe>
                </div>

                <div className="flex flex-col lg:flex-row gap-12">
                  <div className="flex-1">
                    <h1 className="text-3xl font-black mb-4 uppercase italic tracking-tight">{selectedLesson.title}</h1>
                    <div className="flex flex-wrap gap-4 mb-8">
                      <span className="text-amber-500/60 font-black text-[10px] uppercase tracking-widest flex items-center gap-2">
                         <Layout size={12} /> {selectedModule.title}
                      </span>
                      {selectedLesson.tags && (
                        <div className="flex gap-2">
                          {selectedLesson.tags.split(',').map((tag, i) => (
                            <span key={i} className="text-[10px] text-white/20 border border-white/10 px-2 py-1 rounded uppercase tracking-tighter">
                              #{tag.trim()}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                    {/* LESSON DESCRIPTION */}
                    <div 
                      className="lesson-content-html text-white/70"
                      dangerouslySetInnerHTML={{ __html: selectedLesson.description }}
                    />
                  </div>

                  <div className="w-full lg:w-80 space-y-6">
                    <a 
                      href={course.supportUrl} 
                      target="_blank"
                      className="block w-full py-5 bg-white text-black text-center font-black rounded-xl hover:bg-amber-500 transition-all shadow-xl shadow-white/5 uppercase italic"
                    >
                      Suporte Individual
                    </a>

                    {selectedLesson.materials && selectedLesson.materials.length > 0 && (
                      <div className="bg-[#111] border border-white/5 rounded-2xl p-6 shadow-2xl">
                        <h4 className="font-black text-[10px] mb-4 uppercase tracking-[0.2em] text-white/40">Materiais da Aula</h4>
                        <div className="space-y-3">
                          {selectedLesson.materials.map((mat) => (
                            <a 
                              key={mat.id}
                              href={mat.url}
                              target="_blank"
                              download={mat.name}
                              className="flex items-center gap-3 p-3 rounded-xl bg-white/5 border border-white/5 hover:bg-white/10 transition-colors group"
                            >
                              <Download size={16} className="text-amber-500 group-hover:scale-110 transition-transform" />
                              <span className="text-xs font-bold truncate text-white/80">{mat.name}</span>
                            </a>
                          ))}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </>
            ) : (
              <div className="flex flex-col items-center justify-center py-40 text-center">
                 <Play size={64} className="text-white/10 mb-6" />
                 <h2 className="text-2xl font-black text-white/40 uppercase tracking-widest italic">Selecione uma aula para começar</h2>
              </div>
            )}
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="h-full overflow-y-auto custom-scrollbar bg-[#0a0a0a]">
      {/* STUDENT HEADER */}
      <nav className="h-16 flex items-center justify-between px-8 bg-black/50 backdrop-blur-xl border-b border-white/5 sticky top-0 z-50">
        <div className="flex items-center gap-10">
          <div className="flex items-center gap-3">
            <Menu className="text-white/60 lg:hidden" />
            <img src={course.logoUrl} className="w-8 h-8 rounded-lg shadow-lg border border-white/10 object-contain bg-white/5 p-1" alt="Logo" />
            <span className="font-black text-lg tracking-tighter hidden md:block uppercase italic">{course.name}</span>
          </div>
          <div className="hidden lg:flex items-center gap-8 text-[10px] font-black uppercase tracking-widest text-white/60">
            <a href="#" className="text-white border-b-2 border-amber-500 py-5">Vitrine</a>
            <a href="#" className="hover:text-white transition-colors">Meus Treinamentos</a>
            <a href="#" className="hover:text-white transition-colors">Comunidade</a>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <Search size={20} className="text-white/40" />
          <Bell size={20} className="text-white/40" />
          <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center text-black font-black text-[10px] ring-2 ring-white/10 shadow-lg">
            USER
          </div>
        </div>
      </nav>

      {/* STUDENT BANNER */}
      <div className="relative w-full h-[500px] overflow-hidden group">
        <img 
          src={course.bannerUrl} 
          className="w-full h-full object-cover scale-105 group-hover:scale-100 transition-transform duration-[2000ms]" 
          alt="Banner"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-[#0a0a0a] via-[#0a0a0a]/40 to-transparent" />
        <div className="absolute bottom-12 left-12 max-w-2xl">
          <p className="text-amber-500 font-black text-[10px] uppercase tracking-[0.4em] mb-4 italic">Acesso Restrito & Premium</p>
          <h1 className="text-5xl lg:text-8xl font-black mb-8 drop-shadow-2xl uppercase italic tracking-tighter leading-none">{course.name}</h1>
          <button 
            onClick={() => enterLesson(course.modules[0])}
            className="px-12 py-5 bg-white text-black font-black rounded-xl flex items-center gap-4 hover:bg-amber-500 transition-all shadow-2xl scale-100 hover:scale-105 active:scale-95 text-xs tracking-widest italic uppercase"
          >
            <Play fill="black" size={20} /> RETOMAR TREINAMENTO
          </button>
        </div>
      </div>

      {/* MODULES GRID */}
      <section className="px-12 py-20">
        <div className="flex items-center justify-between mb-16">
          <h2 className="text-3xl font-black uppercase italic tracking-tight flex items-center gap-4">
            Módulos do Curso <span className="text-white/10 font-light text-sm not-italic">({course.modules.length})</span>
          </h2>
          <div className="h-[1px] flex-1 mx-12 bg-white/5" />
          <div className="flex gap-2">
            <button className="p-2 border border-white/5 rounded hover:bg-white/5 transition-colors"><ChevronLeft size={20} /></button>
            <button className="p-2 border border-white/5 rounded hover:bg-white/5 transition-colors"><ChevronRight size={20} /></button>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-10">
          {course.modules.map((mod) => (
            <div 
              key={mod.id} 
              className="group cursor-pointer relative"
              onClick={() => enterLesson(mod)}
            >
              <div className={`relative overflow-hidden rounded-2xl ring-1 ring-white/5 group-hover:ring-amber-500/40 transition-all shadow-2xl shadow-black duration-500 ${
                course.moduleThumbnailOrientation === 'horizontal' ? 'aspect-video' : 'aspect-[2/3]'
              }`}>
                <img 
                  src={mod.thumbnailUrl} 
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-[1000ms]" 
                  alt={mod.title}
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/30 to-transparent opacity-90 group-hover:opacity-100 transition-opacity" />

                {/* PLAY ICON OVERLAY */}
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-500 scale-75 group-hover:scale-100">
                  <div className="w-16 h-16 rounded-full bg-amber-500 text-black flex items-center justify-center shadow-2xl ring-4 ring-white/20">
                    <Play fill="black" size={28} className="ml-1" />
                  </div>
                </div>

                <div className="absolute bottom-6 left-6 right-6">
                  <h3 className="font-black text-base lg:text-xl leading-tight drop-shadow-2xl text-white group-hover:text-amber-500 transition-colors uppercase italic tracking-tighter">{mod.title}</h3>
                  <div className="flex items-center justify-between mt-3">
                    <span className="text-[10px] text-white/40 font-black uppercase tracking-widest">{mod.lessons.length} aulas</span>
                    {mod.lessons.length > 0 && (
                      <div className="h-[2px] w-12 bg-white/10 rounded-full overflow-hidden">
                        <div className="h-full bg-amber-500 w-1/3" />
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* STUDENT FOOTER */}
      <footer className="px-12 py-20 bg-[#111] border-t border-white/5 mt-20">
        <div className="flex flex-col lg:flex-row items-center justify-between gap-12">
          <div className="flex flex-col items-center lg:items-start gap-4">
            <img src={course.logoUrl} className="w-12 h-12 rounded-xl grayscale opacity-30 shadow-2xl border border-white/5" alt="Logo grayscale" />
            <p className="text-white/20 text-[10px] uppercase font-black tracking-[0.2em]">© 2025 {course.name} • Todos os direitos reservados</p>
          </div>
          <div className="flex items-center gap-10">
            <a href={course.supportUrl} className="flex items-center gap-3 text-white/40 hover:text-amber-500 transition-all group">
              <div className="w-10 h-10 rounded-full border border-white/5 flex items-center justify-center group-hover:border-amber-500/50">
                <Headphones size={20} />
              </div>
              <span className="text-xs font-black uppercase tracking-widest">Suporte ao Aluno</span>
            </a>
          </div>
        </div>
      </footer>
    </div>
  );
};

