                  <div className="flex items-center justify-between mt-3">
                    <span className="text-[10px] text-white/40 font-black uppercase tracking-widest">{mod.lessons.length} aulas</span>
                    {mod.lessons.length > 0 && (
                      <div className="h-[2px] w-12 bg-white/10 rounded-full overflow-hidden">
                        <div className="h-full bg-amber-500 w-1/3" />
