export default StudentArea;

import React, { useState, useRef } from 'react';
import { CourseConfig, Module, Lesson, Material } from '../types';
import { 
  Save, Plus, Trash2, Edit3, Image as ImageIcon, Layout as LayoutIcon, 
  Video, List, CheckCircle, ChevronDown, ChevronUp, LayoutGrid, Square, RectangleHorizontal, 
  FilePlus, Calendar, Tag, Info, Code, Bold, Italic, Strikethrough, ListOrdered, ListIcon, 
  Link as LinkIcon, Minus, Type, MessageCircle, Rocket, Upload, FileText, X, Settings2
} from 'lucide-react';

interface AdminAreaProps {
  course: CourseConfig;
  onUpdate: (newData: CourseConfig) => void;
}

const AdminArea: React.FC<AdminAreaProps> = ({ course, onUpdate }) => {
  const [activeTab, setActiveTab] = useState<'general' | 'modules' | 'appearance'>('modules');
  const [formData, setFormData] = useState<CourseConfig>(course);
  const [showSaveToast, setShowSaveToast] = useState(false);
  const [expandedModule, setExpandedModule] = useState<string | null>(formData.modules[0]?.id || null);
  const [expandedLessonSections, setExpandedLessonSections] = useState<Record<string, string | null>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const currentUploadTarget = useRef<{ modId: string, lessonId: string } | null>(null);
  const currentImageTarget = useRef<{ type: 'logo' | 'banner' | 'module' | 'lesson', modId?: string, lessonId?: string } | null>(null);

  const handleSave = () => {
    onUpdate(formData);
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  const toggleLessonSection = (lessonId: string, section: string) => {
    setExpandedLessonSections(prev => ({
      ...prev,
      [lessonId]: prev[lessonId] === section ? null : section
    }));
  };

  const insertHtmlAtCursor = (moduleId: string, lessonId: string, htmlToInsert: string) => {
    const lesson = formData.modules.find(m => m.id === moduleId)?.lessons.find(l => l.id === lessonId);
    if (!lesson) return;
    const currentDescription = lesson.description || '';
    updateLesson(moduleId, lessonId, { description: currentDescription + '\n' + htmlToInsert });
  };

  const addModule = () => {
    const newModule: Module = {
      id: `mod-${Date.now()}`,
      title: 'Novo Módulo Premium',
      thumbnailUrl: 'https://images.unsplash.com/photo-1557683316-973673baf926?q=80&w=800&auto=format&fit=crop',
      lessons: []
    };
    setFormData(prev => ({ ...prev, modules: [...prev.modules, newModule] }));
    setExpandedModule(newModule.id);
  };

  const updateModule = (id: string, updates: Partial<Module>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === id ? { ...m, ...updates } : m)
    }));
  };

  const addLesson = (moduleId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          const modThumb = m.thumbnailUrl;
          return {
            ...m,
            lessons: [...m.lessons, {
              id: `les-${Date.now()}`,
              title: 'Nova Aula de Elite',
              thumbnailUrl: modThumb,
              videoUrl: 'https://www.youtube.com/embed/dQw4w9WgXcQ',
              description: '<p>Conteúdo programático...</p>',
              materials: [],
              tags: '',
              releaseDays: 0
            }]
          };
        }
        return m;
      })
    }));
  };

  const updateLesson = (moduleId: string, lessonId: string, updates: Partial<Lesson>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return {
            ...m,
            lessons: m.lessons.map(l => l.id === lessonId ? { ...l, ...updates } : l)
          };
        }
        return m;
      })
    }));
  };

  const triggerFileUpload = (modId: string, lessonId: string) => {
    currentUploadTarget.current = { modId, lessonId };
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  const triggerImageUpload = (target: typeof currentImageTarget.current) => {
    currentImageTarget.current = target;
    if (imageInputRef.current) {
      imageInputRef.current.click();
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    const target = currentImageTarget.current;
    if (!file || !target) return;

    const allowedExtensions = ['jpg', 'jpeg', 'png', 'webp', 'gif', 'svg'];
    const extension = file.name.split('.').pop()?.toLowerCase();

    if (!extension || !allowedExtensions.includes(extension)) {
      alert('Por favor, selecione uma imagem válida (JPG, PNG, WEBP, GIF ou SVG).');
      return;
    }

    const imageUrl = URL.createObjectURL(file);

    if (target.type === 'logo') {
      setFormData(prev => ({ ...prev, logoUrl: imageUrl }));
    } else if (target.type === 'banner') {
      setFormData(prev => ({ ...prev, bannerUrl: imageUrl }));
    } else if (target.type === 'module' && target.modId) {
      updateModule(target.modId, { thumbnailUrl: imageUrl });
    } else if (target.type === 'lesson' && target.modId && target.lessonId) {
      updateLesson(target.modId, target.lessonId, { thumbnailUrl: imageUrl });
    }

    e.target.value = '';
    currentImageTarget.current = null;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    const target = currentUploadTarget.current;
    if (!files || !target) return;

    const mod = formData.modules.find(m => m.id === target.modId);
    const lesson = mod?.lessons.find(l => l.id === target.lessonId);
    if (!lesson) return;

    const allowedExtensions = ['jpg', 'jpeg', 'gif', 'png', 'bmp', 'pdf', 'zip', 'rar', 'epub', 'xls', 'xlsx', 'xlsm', 'mp3', 'doc', 'docx', 'ppt', 'pptx'];
    const MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB
    const MAX_FILES = 10;

    const currentFilesCount = lesson.materials?.length || 0;
    const remainingSlots = MAX_FILES - currentFilesCount;

    if (remainingSlots <= 0) {
      alert(`Você já atingiu o limite de ${MAX_FILES} arquivos para esta aula.`);
      return;
    }

    const newMaterials: Material[] = [];
    const filesArray = Array.from(files).slice(0, remainingSlots);

    filesArray.forEach(file => {
      const extension = file.name.split('.').pop()?.toLowerCase();
      if (!extension || !allowedExtensions.includes(extension)) {
        alert(`Formato de arquivo não permitido: ${file.name}`);
        return;
      }
      if (file.size > MAX_FILE_SIZE) {
        alert(`O arquivo ${file.name} excede o limite de 100MB.`);
        return;
      }

      const fileUrl = URL.createObjectURL(file);
      newMaterials.push({
        id: `mat-${Date.now()}-${Math.random()}`,
        name: file.name,
        url: fileUrl
      });
    });

    if (newMaterials.length > 0) {
      setFormData(prev => ({
        ...prev,
        modules: prev.modules.map(m => m.id === target.modId ? {
          ...m,
          lessons: m.lessons.map(l => l.id === target.lessonId ? { 
            ...l, 
            materials: [...(l.materials || []), ...newMaterials] 
          } : l)
        } : m)
      }));
    }

    e.target.value = '';
    currentUploadTarget.current = null;
  };

  const updateMaterial = (modId: string, lessonId: string, matId: string, updates: Partial<Material>) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === modId ? {
        ...m,
        lessons: m.lessons.map(l => l.id === lessonId ? {
          ...l,
          materials: l.materials.map(mat => mat.id === matId ? { ...mat, ...updates } : mat)
        } : l)
      } : m)
    }));
  };

  const deleteMaterial = (modId: string, lessonId: string, matId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => m.id === modId ? {
        ...m,
        lessons: m.lessons.map(l => l.id === lessonId ? {
          ...l,
          materials: l.materials.filter(mat => mat.id !== matId)
        } : l)
      } : m)
    }));
  };

  const deleteModule = (moduleId: string) => {
    setFormData(prev => ({ ...prev, modules: prev.modules.filter(m => m.id !== moduleId) }));
  };

  const deleteLesson = (moduleId: string, lessonId: string) => {
    setFormData(prev => ({
      ...prev,
      modules: prev.modules.map(m => {
        if (m.id === moduleId) {
          return { ...m, lessons: m.lessons.filter(l => l.id !== lessonId) };
        }
        return m;
      })
    }));
  };

  return (
    <div className="max-w-7xl mx-auto p-10 bg-[#0a0a0a] min-h-screen">
      {/* Hidden File Input for Materials */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        className="hidden" 
        multiple
        accept=".jpg,.jpeg,.gif,.png,.bmp,.pdf,.zip,.rar,.epub,.xls,.xlsx,.xlsm,.mp3,.doc,.docx,.ppt,.pptx"
      />

      {/* Hidden File Input for Images (Logo, Banner, Thumbs) */}
      <input 
        type="file" 
        ref={imageInputRef} 
        onChange={handleImageChange} 
        className="hidden" 
        accept="image/*"
      />

      {showSaveToast && (
        <div className="fixed bottom-10 right-10 z-[200] animate-in fade-in slide-in-from-bottom-5 duration-300 bg-amber-500 text-black px-8 py-4 rounded-xl shadow-2xl flex items-center gap-3">
          <CheckCircle size={24} />
          <span className="font-black uppercase tracking-tight">Publicado com Sucesso!</span>
        </div>
      )}

      <div className="flex items-center justify-between mb-12">
        <div>
          <h1 className="text-4xl font-black tracking-tighter uppercase italic text-white">Painel do Produtor</h1>
          <p className="text-white/40 mt-2 font-medium">Personalize a experiência premium dos seus alunos.</p>
        </div>
        <button 
          onClick={handleSave}
          className="bg-amber-500 text-black px-12 py-4 rounded font-black hover:bg-white transition-all shadow-xl shadow-amber-500/10 flex items-center gap-3"
        >
          <Save size={20} /> SALVAR ALTERAÇÕES
        </button>
      </div>

      <div className="grid grid-cols-12 gap-12">
        <div className="col-span-12 lg:col-span-3 space-y-4">
          <button onClick={() => setActiveTab('general')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'general' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <LayoutIcon size={20} /> GERAL
          </button>
          <button onClick={() => setActiveTab('modules')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'modules' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <List size={20} /> CONTEÚDO
          </button>
          <button onClick={() => setActiveTab('appearance')} className={`w-full flex items-center gap-4 px-6 py-5 rounded-lg font-bold transition-all border ${activeTab === 'appearance' ? 'bg-amber-500 text-black border-amber-500 shadow-lg' : 'bg-[#111] text-white/60 border-white/5 hover:border-white/20'}`}>
            <ImageIcon size={20} /> VISUAL
          </button>
        </div>

        <div className="col-span-12 lg:col-span-9">
          {activeTab === 'general' && (
            <div className="bg-[#111] border border-white/5 rounded-2xl p-10 space-y-10">
              <div className="grid grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black text-white/40 uppercase tracking-widest">Orientação da Thumbnail do Módulo</label>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => setFormData({...formData, moduleThumbnailOrientation: 'horizontal'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleThumbnailOrientation === 'horizontal' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <RectangleHorizontal size={16} /> HORIZONTAL (16:9)
                    </button>
                    <button 
                      onClick={() => setFormData({...formData, moduleThumbnailOrientation: 'vertical'})}
                      className={`flex-1 py-3 rounded-lg border flex items-center justify-center gap-2 font-bold text-xs ${formData.moduleThumbnailOrientation === 'vertical' ? 'bg-amber-500 border-amber-500 text-black' : 'border-white/10 text-white/40 hover:bg-white/5'}`}
                    >
                      <Square size={16} /> VERTICAL (2:3)
                    </button>
                  </div>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-8">
