  // Helper to convert standard video links to embed links
  const getEmbedUrl = (url: string) => {
    if (!url) return '';

    // Handle YouTube
    if (url.includes('youtube.com/watch?v=')) {
      const id = url.split('v=')[1]?.split('&')[0];
      return `https://www.youtube.com/embed/${id}`;
    }
    if (url.includes('youtu.be/')) {
      const id = url.split('youtu.be/')[1]?.split('?')[0];
      return `https://www.youtube.com/embed/${id}`;
    }

    // Handle Vimeo
    if (url.includes('vimeo.com/') && !url.includes('player.vimeo.com')) {
      // Handles links like https://vimeo.com/1163600824 or with query params
      const parts = url.split('vimeo.com/')[1];
      const id = parts.split('?')[0].split('/')[0];
      return `https://player.vimeo.com/video/${id}`;
    }

    return url;
  };

  const enterLesson = (mod: Module, lesson?: Lesson) => {
    if (!mod.lessons || mod.lessons.length === 0) {
      alert("Este módulo ainda não possui aulas cadastradas.");
      return;
